module median_filter (
    input a,
    input b,
    input c,
    output reg anti_median
);
    always @(*) begin
        if ((a >= b && a <= c) || (a <= b && a >= c))
            anti_median = a;
        else if ((b >= a && b <= c) || (b <= a && b >= c))
            anti_median = b;
        else
            anti_median = c;
    end
endmodule
